const chatInput = $input.first().json.chatInput || '';
const urlMatch = chatInput.match(/https?:\/\/[^\s]+/);
const url = urlMatch ? urlMatch[0].trim() : 'https://example.com';
return [{ json: { chatInput, url } }];

const chatInput = $('Extract URL').first().json.chatInput;
const raw = $input.first().json;
let pageContent = raw.body ?? raw.data ?? raw.text ?? JSON.stringify(raw);
if (typeof pageContent === 'string') {
  pageContent = pageContent.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '').replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  if (pageContent.length > 2500) pageContent = pageContent.slice(0, 2500) + '...';
}
return [{ json: { chatInput, pageContent } }];

const { chatInput, pageContent } = $input.first().json;
const userMessage = `Contenu du site :\n${pageContent}\n\nQuestion : Propose une stratégie marketing en 5 points (secteur, cible, objectifs, thèmes, planning). Réponds en français.`;
const body = {
  model: 'tinyllama',
  stream: false,
  messages: [
    { role: 'system', content: 'Tu es un expert marketing. Réponds en français par une stratégie de contenu courte et structurée.' },
    { role: 'user', content: userMessage }
  ]
};
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://host.docker.internal:11434/api/chat',
  body,
  json: true,
  skipSslCertificateValidation: true
});
const content = response.message?.content ?? response.body?.message?.content ?? response.content;
const text = (typeof content === 'string' ? content : (response.message || response.body?.message || 'Pas de réponse.'));
let out = typeof text === 'string' ? text : (text?.content ?? JSON.stringify(text));
if (typeof out === 'string') {
  if (/^Tu es un consultant/i.test(out)) out = out.replace(/^Tu es un consultant[^\n]*\.?\s*\n?/gi, '').replace(/^Tu analys[^\n]*\.?\s*\n?/gi, '').trim();
  const echo = out.indexOf('---');
  if (echo > 20 && /Demande de l'utilisateur|Analyse le site/.test(out.slice(echo))) out = out.slice(0, echo).trim();
}
if (typeof out === 'string' && out.length < 40) out = 'TinyLlama n\'a pas généré de stratégie. Réessaie avec https://example.com';
return [{ json: { text: out } }];
